import type { IGomokuPiece } from '@algorithm.ts/gomoku'
import { GomokuDirectionTypes, GomokuDirections } from '@algorithm.ts/gomoku'
import { GomokuInstructionType } from './constant'
import type { IGomokuInstruction } from './state'

export function runInstructs(instructions: ReadonlyArray<IGomokuInstruction>): IGomokuPiece[] {
  const pieces: IGomokuPiece[] = []
  for (const instruction of instructions) {
    switch (instruction.type) {
      case GomokuInstructionType.RETRACT: {
        pieces.splice(pieces.length - instruction.payload, instruction.payload)
        break
      }
      case GomokuInstructionType.MOVE: {
        const { r, c, p } = instruction.payload
        pieces.push({ r, c, p })
        break
      }
      default:
    }
  }
  return pieces
}

const halfDirectionTypes = GomokuDirectionTypes.rightHalf

export function checkWinner(
  pieces: ReadonlyArray<IGomokuPiece>,
  MAX_ROW: number,
  MAX_COL: number,
  MAX_ADJACENT = 5,
): -1 | 0 | 1 {
  const board = new Int32Array(MAX_ROW * MAX_COL).fill(-1)
  for (const { r, c, p } of pieces) board[r * MAX_ROW + c] = p

  const idx = (r: number, c: number): number => r * MAX_ROW + c
  const isValidPos = (r: number, c: number): boolean =>
    r >= 0 && r < MAX_ROW && c >= 0 && c < MAX_COL

  for (const dirType of halfDirectionTypes) {
    const [dr, dc] = GomokuDirections[dirType]
    for (let r = 0; r < MAX_ROW; ++r) {
      for (let c = 0; c < MAX_COL; ++c) {
        const playerId: number = board[idx(r, c)]
        if (playerId < 0) continue
        let cnt = 1
        for (let r2 = r + dr, c2 = c + dc; isValidPos(r2, c2); r2 += dr, c2 += dc) {
          if (board[idx(r2, c2)] !== playerId) break
          cnt += 1
        }
        if (cnt >= MAX_ADJACENT) {
          if (playerId !== 0 && playerId !== 1) {
            throw new Error(`[checkWinner] Bad player(${playerId}) on piece (${r}, ${c}).`)
          }
          return playerId
        }
      }
    }
  }
  return -1
}
