import { calcCssBackground, mergeStyleSets } from '@kyokuya/core-util'
import { useThrowRandomConfetti } from '@kyokuya/react-confetti'
import { GameRunningStatus } from '@kyokuya/react-game-core'
import GamePausedIcon from '@mui/icons-material/PauseCircleFilled'
import GamePendingIcon from '@mui/icons-material/PlayArrow'
import GameRefreshIcon from '@mui/icons-material/Refresh'
import Button from '@mui/material/Button'
import React from 'react'
import { GomokuActionType, useGomokuContext } from '../context'
import type { IGomokuPlayer } from '../types'

export const GameOverlay: React.FC = () => {
  const [winnerIdx, gameStatus, players, dispatch] = useGomokuContext(({ state, dispatch }) => [
    state.winner,
    state.gameStatus,
    state.players,
    dispatch,
  ])
  const throwConfetti = useThrowRandomConfetti()

  const winner: IGomokuPlayer | undefined = players[winnerIdx]
  React.useEffect(() => {
    if (gameStatus === GameRunningStatus.FINISHED && winner !== undefined) {
      void throwConfetti()
    }
  }, [gameStatus, winner, throwConfetti])

  const classes = useStyles()
  return React.useMemo(() => {
    const start = (): void => dispatch({ type: GomokuActionType.START })
    const resume = (): void => dispatch({ type: GomokuActionType.RESUME })
    const restart = (): void => dispatch({ type: GomokuActionType.RESTART })

    switch (gameStatus) {
      case GameRunningStatus.PENDING: {
        return (
          <div className={classes.overlay}>
            <Button
              className={classes.button}
              variant="contained"
              color="primary"
              startIcon={<GamePendingIcon />}
              onClick={start}
            >
              Start
            </Button>
          </div>
        )
      }
      case GameRunningStatus.PAUSED: {
        return (
          <div className={classes.overlay}>
            <Button
              className={classes.button}
              variant="contained"
              color="primary"
              startIcon={<GamePausedIcon />}
              onClick={resume}
            >
              Resume
            </Button>
          </div>
        )
      }
      case GameRunningStatus.FINISHED: {
        return (
          <div className={classes.overlay}>
            <div className={classes.finishedBanner}>
              {winner !== undefined ? (
                <div className={classes.blessing}>
                  <div className={classes.winner}>
                    <span
                      key="avatar"
                      className={classes.winnerAvatar}
                      style={{
                        background: calcCssBackground(winner.preference.pieceFillStyle),
                        backgroundSize: 'cover',
                      }}
                    />
                    <span key="name" className={classes.winnerName}>
                      {winner.name}
                    </span>
                  </div>
                  win🎉
                </div>
              ) : (
                <p>Draw!</p>
              )}
              <Button
                className={classes.button}
                variant="contained"
                color="primary"
                startIcon={<GameRefreshIcon />}
                onClick={restart}
              >
                New
              </Button>
            </div>
          </div>
        )
      }
      default:
        return null
    }
  }, [gameStatus, classes, dispatch, winner])
}

const useStyles = () => {
  return React.useMemo(
    () =>
      mergeStyleSets({
        overlay: {
          position: 'relative',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          height: '100%',
          width: '100%',
          userSelect: 'none',
        },
        confettiCanvas: {
          top: 0,
          bottom: 0,
          left: 0,
          right: 0,
          width: '100%',
          height: '100%',
        },
        button: {
          '&&, &&:hover': {
            boxShadow: '4px 4px 16px 0px hsl(0deg 0% 0% / 0.75)',
          },
        },
        finishedBanner: {
          position: 'relative',
          display: 'flex',
          flexDirection: 'column',
          justifyContent: 'center',
          padding: 0,
          margin: 0,
          fontSize: 32,
        },
        blessing: {
          display: 'flex',
          alignItems: 'center',
          marginBottom: '1rem',
        },
        winner: {
          display: 'flex',
          flexDirection: 'column',
          alignItems: 'center',
          marginRight: 16,
        },
        winnerAvatar: {
          display: 'inline-block',
          width: 32,
          height: 32,
          borderRadius: '50%',
        },
        winnerName: {
          color: '#333',
          fontSize: 12,
        },
      }),
    [],
  )
}
