import type { IColorOrImage } from '@kyokuya/core-util'
import { mergeStyleSets } from '@kyokuya/core-util'
import { GameRunningStatus } from '@kyokuya/react-game-core'
import { useEvent } from '@kyokuya/react-hooks'
import React from 'react'
import { DuelPlayer } from '../component/DuelPlayer'
import { GomokuActionType, useGomokuContext } from '../context'
import { GomokuPlayerSettings } from './GomokuPlayerSettings'

export interface IDuelPlayerContainerProps {
  containerRef: React.RefObject<HTMLDivElement>
}

export const DuelPlayerContainer: React.FC<IDuelPlayerContainerProps> = props => {
  const [[player0, player1], gameStatus, mover, dispatch] = useGomokuContext(
    ({ state, dispatch }) => [state.players, state.gameStatus, state.mover, dispatch],
  )

  const [editingPlayerId, setEditingPlayerId] = React.useState<number | null>(null)

  const isRunning: boolean = gameStatus === GameRunningStatus.RUNNING
  const isEditable: boolean = gameStatus === GameRunningStatus.PENDING

  const events = {
    onCancel: useEvent((): void => setEditingPlayerId(null)),
    onEditPlayer0: useEvent((): void => setEditingPlayerId(0)),
    onEditPlayer1: useEvent((): void => setEditingPlayerId(1)),
    onPlayer0AvatarChange: useEvent((avatar: IColorOrImage): void => {
      dispatch({
        type: GomokuActionType.MODIFY_PLAYER,
        payload: {
          id: 0,
          preference: {
            pieceFillStyle: avatar,
          },
        },
      })
    }),
    onPlayer1AvatarChange: useEvent((avatar: IColorOrImage): void => {
      dispatch({
        type: GomokuActionType.MODIFY_PLAYER,
        payload: {
          id: 1,
          preference: {
            pieceFillStyle: avatar,
          },
        },
      })
    }),
  }

  const classes = useStyles()

  return (
    <div className={classes.container}>
      <DuelPlayer
        key="player0"
        position="left"
        className={classes.player0}
        name={player0.name}
        type={player0.type}
        avatar={player0.preference.pieceFillStyle}
        disabled={!isEditable}
        running={isRunning}
        thinking={mover === 0}
        onEdit={events.onEditPlayer0}
        onAvatarChange={events.onPlayer0AvatarChange}
      />
      <span className={classes.versus}>VS</span>
      <DuelPlayer
        key="player1"
        position="right"
        className={classes.player1}
        name={player1.name}
        type={player1.type}
        avatar={player1.preference.pieceFillStyle}
        disabled={!isEditable}
        running={isRunning}
        thinking={mover === 1}
        onEdit={events.onEditPlayer1}
        onAvatarChange={events.onPlayer1AvatarChange}
      />
      {editingPlayerId != null && (
        <GomokuPlayerSettings
          containerRef={props.containerRef}
          visible={true}
          playerId={editingPlayerId}
          onClose={events.onCancel}
        />
      )}
    </div>
  )
}

const useStyles = () => {
  return mergeStyleSets({
    container: {
      display: 'flex',
      alignItems: 'center',
      maxWidth: 'min(90vw, 400px)',
      height: '3rem',
      width: '100%',
      margin: 'auto',
    },
    player0: {
      flex: '1 1 0',
      display: 'flex',
    },
    player1: {
      flex: '1 1 0',
      display: 'flex',
    },
    versus: {
      flex: '0 0 auto',
      margin: '0 36px',
    },
  })
}
