export interface IWorkerRequest<T extends string = string, D = unknown> {
  /**
   * Request id.
   */
  id: number
  /**
   * Service type.
   */
  type: T
  /**
   * Request data.
   */
  data: D
}

export interface IWorkerResponse<D> {
  /**
   * Request id.
   */
  id: number
  /**
   * Response data.
   */
  data: D | null
  /**
   * Error message.
   */
  error?: string
}

export interface IKyokuyaWorkerProps<D> {
  canUseDOM: boolean
  scriptURL: string | URL
  options?: WorkerOptions
  onResponse(data: MessageEvent<IWorkerResponse<D>>): Promise<void> | void
}

export class KyokuyaWorker<T extends string, IRequestData, IResponseData> {
  protected readonly _worker: Worker | null
  protected _running: boolean

  constructor(props: IKyokuyaWorkerProps<IResponseData>) {
    this._running = false
    this._worker = null
    if (props.canUseDOM && typeof Worker !== 'undefined') {
      const { scriptURL, options, onResponse } = props
      const worker = new Worker(scriptURL, options)
      worker.onmessage = e => {
        this._running = false
        void onResponse(e)
      }
      this._worker = worker
    }
  }

  public get isRunning(): boolean {
    return this._running
  }

  public request(data: IWorkerRequest<T, IRequestData>): void {
    if (!this._running) {
      this._running = true
      this._worker?.postMessage(data)
    }
  }
}
