import type { IGomokuPiece } from '@algorithm.ts/gomoku'
import { noEffectAssign } from '@kyokuya/core-util'
import { GameRunningStatus } from '@kyokuya/react-game-core'
import { produce } from 'immer'
import type React from 'react'
import type { IGomokuAction } from './action'
import { GomokuActionType, GomokuInstructionType } from './constant'
import type { IGomokuState } from './state'
import { checkWinner } from './util'

const errorTitle = '[gomoku reducer]'

export const gomokuReducer: React.Reducer<IGomokuState, IGomokuAction> = (
  prevState,
  action,
): IGomokuState => {
  const { gameStatus } = prevState
  switch (action.type) {
    case GomokuActionType.FLIP_PLAYER: {
      if (gameStatus !== GameRunningStatus.PENDING) return prevState
      const [player0, player1] = prevState.players
      return {
        ...prevState,
        players: [player1, player0],
        forceRenderTick: prevState.forceRenderTick + 1,
      }
    }
    case GomokuActionType.MODIFY_PLAYER: {
      if (gameStatus === GameRunningStatus.FINISHED) return prevState
      const data = action.payload
      if (data.id !== 0 && data.id !== 1) {
        console.error(errorTitle, 'bad action:', action)
        return prevState
      }

      const curPlayer = prevState.players[data.id]
      const nextPlayer = noEffectAssign(curPlayer, {
        name: data.name,
        type: data.type,
        preference: noEffectAssign(curPlayer.preference, {
          pieceFillStyle: data.preference?.pieceFillStyle,
          pieceStrokeStyle: data.preference?.pieceStrokeStyle,
        }),
      })
      return nextPlayer === curPlayer
        ? prevState
        : {
            ...prevState,
            players: prevState.players.map((player, playerId) =>
              playerId === data.id ? nextPlayer : player,
            ),
            forceRenderTick: prevState.forceRenderTick + 1,
          }
    }
    case GomokuActionType.MODIFY_PREFERENCE: {
      if (gameStatus === GameRunningStatus.FINISHED) return prevState
      const { preference } = action.payload
      return {
        ...prevState,
        preference: {
          ...prevState.preference,
          ...preference,
        },
        forceRenderTick: prevState.forceRenderTick + 1,
      }
    }
    case GomokuActionType.MOVE: {
      if (gameStatus !== GameRunningStatus.RUNNING) return prevState
      const { r, c } = action.payload
      if (prevState.pieces.some(piece => piece.r === r && piece.c === c)) return prevState

      const { MAX_ROW, MAX_COL, mover } = prevState
      const piece: IGomokuPiece = { r, c, p: mover }
      const nextPieces: IGomokuPiece[] = [...prevState.pieces, piece]
      const winner = checkWinner(nextPieces, MAX_ROW, MAX_COL)
      const isFinished = winner >= 0 || nextPieces.length === MAX_ROW * MAX_COL

      return {
        ...prevState,
        gameStatus: isFinished ? GameRunningStatus.FINISHED : gameStatus,
        winner,
        pieces: nextPieces,
        mover: (mover ^ 1) as 0 | 1,
        attemptTick: prevState.attemptTick + 1,
        instructions: [
          ...prevState.instructions,
          {
            type: GomokuInstructionType.MOVE,
            payload: piece,
            timestamp: new Date().toISOString(),
          },
        ],
      }
    }
    case GomokuActionType.PAUSE: {
      if (gameStatus === GameRunningStatus.RUNNING) {
        return produce(prevState, draftState => {
          // eslint-disable-next-line no-param-reassign
          draftState.gameStatus = GameRunningStatus.PAUSED
        })
      }
      return prevState
    }
    case GomokuActionType.RESET: {
      if (gameStatus === GameRunningStatus.PENDING) {
        const { MAX_ROW = prevState.MAX_ROW, MAX_COL = prevState.MAX_COL } = action.payload ?? {}
        return {
          ...prevState,
          MAX_ROW,
          MAX_COL,
          winner: -1,
          mover: 0,
          pieces: [],
          instructions: [],
          gameTick: prevState.gameTick + 1,
          attemptTick: 0,
        }
      }
      return prevState
    }
    case GomokuActionType.RESTART: {
      if (gameStatus !== GameRunningStatus.PENDING) {
        return {
          ...prevState,
          gameStatus: GameRunningStatus.PENDING,
          winner: -1,
          mover: 0,
          pieces: [],
          instructions: [],
          gameTick: prevState.gameTick + 1,
          attemptTick: 0,
        }
      }
      return prevState
    }
    case GomokuActionType.RESUME: {
      if (gameStatus === GameRunningStatus.PAUSED) {
        return produce(prevState, draftState => {
          // eslint-disable-next-line no-param-reassign
          draftState.gameStatus = GameRunningStatus.RUNNING
        })
      }
      return prevState
    }
    case GomokuActionType.RETRACT: {
      // Only worked in running state or finished state.
      if (gameStatus === GameRunningStatus.RUNNING || gameStatus === GameRunningStatus.FINISHED) {
        let idx = prevState.pieces.length - 1
        for (; idx >= 0; --idx) {
          if (prevState.pieces[idx].p === prevState.mover) break
        }
        if (idx < 0) return prevState // Not enough pieces to retract.

        const steps: number = prevState.pieces.length - idx
        const pieces: IGomokuPiece[] = prevState.pieces.slice(0, prevState.pieces.length - steps)
        const nextMover: 0 | 1 = (pieces.length & 1) as 0 | 1

        return {
          ...prevState,
          gameStatus: GameRunningStatus.RUNNING,
          pieces,
          winner: -1,
          mover: nextMover,
          attemptTick: prevState.attemptTick + 1,
          instructions: prevState.instructions.concat({
            type: GomokuInstructionType.RETRACT,
            payload: steps,
            timestamp: new Date().toISOString(),
          }),
        }
      }
      return prevState
    }
    case GomokuActionType.START: {
      if (gameStatus === GameRunningStatus.PENDING) {
        return produce(prevState, draftState => {
          // eslint-disable-next-line no-param-reassign
          draftState.gameStatus = GameRunningStatus.RUNNING
        })
      }
      return prevState
    }
    default:
      console.error(errorTitle, 'bad action:', action)
      return prevState
  }
}
