import { css, cx, keyframes } from '@emotion/css'
import { calcCssColor } from '@kyokuya/core-util'
import { GameRunningStatus } from '@kyokuya/react-game-core'
import { useEvent } from '@kyokuya/react-hooks'
import React from 'react'
import { useGomokuContext } from '../context'
import { GomokuDrawer } from '../core/drawer/GomokuDrawer'
import type { IPreferenceSettingsProvider } from '../core/drawer/GomokuPieceDrawer'
import { GomokuPieceDrawer } from '../core/drawer/GomokuPieceDrawer'
import { useMover } from '../hook/useMover'

export interface IGomokuBoardProps {
  /**
   * Gomoku board overlay.
   */
  overlay?: React.ReactNode
  /**
   * CSS class name.
   */
  className?: string
}

export const GameBoard: React.FC<IGomokuBoardProps> = props => {
  const { overlay, className } = props
  const [GOMOKU_SIZE, pieces, gameStatus, players, _borderColor, forceRenderTick] =
    useGomokuContext(({ state }) => [
      state.MAX_ROW,
      state.pieces,
      state.gameStatus,
      state.players,
      state.preference.borderColor,
      state.forceRenderTick,
    ])

  const canvasRef = React.useRef<HTMLCanvasElement>(null)

  const mover = useMover()
  const onGomokuBoardClicked = useEvent((r: number, c: number): void => {
    if (r >= 0 && r < GOMOKU_SIZE && c >= 0 && c < GOMOKU_SIZE) {
      void mover.move({ r, c })
    }
  })
  const getPreferenceSettings = useEvent<IPreferenceSettingsProvider>(id => players[id].preference)
  const draw = useEvent(async (): Promise<void> => {
    await gomokuDrawer?.draw(pieces)
  })

  const [gomokuDrawer, setGomokuDrawer] = React.useState<GomokuDrawer | null>(null)
  React.useEffect(() => {
    const pieceDrawer = new GomokuPieceDrawer(getPreferenceSettings)
    const nextGomokuDrawer = new GomokuDrawer({
      canvas: canvasRef.current,
      lines: 15,
      pieces: [],
      pieceDrawer,
      listeners: { onClick: onGomokuBoardClicked },
    })
    setGomokuDrawer(nextGomokuDrawer)
    return (): void => nextGomokuDrawer.destroy()
  }, [onGomokuBoardClicked, getPreferenceSettings])

  const borderColor = calcCssColor(_borderColor)
  React.useEffect(() => {
    if (gomokuDrawer != null) {
      gomokuDrawer.reset({
        canvas: canvasRef.current,
        GOMOKU_SIZE,
        styles: {
          gridLineColor: borderColor,
        },
      })
      void draw()
    }
  }, [gomokuDrawer, GOMOKU_SIZE, borderColor, draw])
  React.useEffect(() => {
    void gomokuDrawer?.draw(pieces)
  }, [gomokuDrawer, pieces, forceRenderTick])

  const classes = useStyles()
  return (
    <div className={cx(classes.container, className)}>
      <div key="overlay" className={cx(classes.overlay, classes[`overlay_${gameStatus}`])}>
        {overlay}
      </div>
      <canvas ref={canvasRef} />
    </div>
  )
}

const useStyles = () => {
  return {
    container: css`
      position: relative;
      box-sizing: content-box;
      display: inline-block;
      width: 100%;
      height: 100%;
      padding: 0;
      border: 0;
      margin: 0;
      font-family: Consolas, 'Source Code Pro', 'Roboto Mono', monospace, sans-serif;
    `,
    overlay: css`
      z-index: 2;
      position: absolute;
      top: 0;
      left: 0;
      right: 0;
      bottom: 0;
      display: none;
      width: 100%;
      height: 100%;
      overflow: hidden;
      background: linear-gradient(
        45deg,
        hsl(30deg 20% 90% / 0.2),
        hsl(210deg 20% 100% / 0.3)
      );
    `,
    [`overlay_${GameRunningStatus.PENDING}`]: css`
      && {
        display: block;
        backdrop-filter: blur(1px);
      }
    `,
    [`overlay_${GameRunningStatus.RUNNING}`]: css`
      && {
        display: none;
      }
    `,
    [`overlay_${GameRunningStatus.PAUSED}`]: css`
      && {
        display: block;
        backdrop-filter: blur(4px);
      }
    `,
    [`overlay_${GameRunningStatus.FINISHED}`]: css`
      && {
        display: block;
        backdrop-filter: blur(4px);
        color: #ff00ff;
        animation: 1s 0s ${animations.finished} ease-in-out;
      }
    `,
  }
}

const animations = {
  finished: keyframes`
    0% {
      transform: translate(0, -100px);
    }
    80% {
      transform: translate(0, 20px);
    }
    90% {
      transform: translate(0, -10px);
    }
    95% {
      transform: translate(0, 2px);
    }
    100% {
      transform: translate(0, 0);
    }
  `,
}
