import type { IFormDialogClasses, IFormItems } from '@kyokuya/core-component'
import {
  FormDialog,
  createFormItemBackground,
  createFormItemEnum,
  createFormItemString,
} from '@kyokuya/core-component'
import type { IColor, IColorOrImage } from '@kyokuya/core-util'
import { mergeStyleSets, removeUndefinedValues } from '@kyokuya/core-util'
import { GameRunningStatus } from '@kyokuya/react-game-core'
import { useEvent } from '@kyokuya/react-hooks'
import React from 'react'
import {
  GomokuActionType,
  GomokuPlayerType,
  defaultGomokuState,
  useGomokuContext,
} from '../context'

interface IGomokuPlayerSettingsData {
  name: string
  type: GomokuPlayerType
  pieceFill: IColorOrImage
  pieceStroke?: IColor
}

export interface IGomokuPlayerSettingsProps {
  containerRef: React.RefObject<HTMLDivElement>
  playerId: number
  visible: boolean
  onClose(): void
}

export const GomokuPlayerSettings: React.FC<IGomokuPlayerSettingsProps> = props => {
  const { playerId } = props
  const [gameStatus, player, dispatch] = useGomokuContext(({ state, dispatch }) => [
    state.gameStatus,
    state.players[playerId],
    dispatch,
  ])

  const factoryData = React.useMemo<IGomokuPlayerSettingsData>(() => {
    const defaultPlayer = defaultGomokuState.players[playerId]
    return {
      name: defaultPlayer.name,
      type: defaultPlayer.type,
      pieceFill: defaultPlayer.preference.pieceFillStyle,
      pieceStroke: defaultPlayer.preference.pieceStrokeStyle,
    }
  }, [playerId])

  const initialData = React.useMemo<IGomokuPlayerSettingsData>(
    () => ({
      name: player.name,
      type: player.type,
      pieceFill: player.preference.pieceFillStyle,
      pieceStroke: player.preference.pieceStrokeStyle,
    }),
    [player],
  )

  const isPending: boolean = gameStatus === GameRunningStatus.PENDING
  const isFinished: boolean = gameStatus === GameRunningStatus.FINISHED
  const formItems = React.useMemo<IFormItems<IGomokuPlayerSettingsData>>(
    () => ({
      name: {
        label: 'Name',
        disabled: isFinished,
        ContentRenderer: createFormItemString({
          componentName: 'GomokuSettingPlayerName',
        }),
      },
      type: {
        label: 'Type',
        disabled: !isPending,
        ContentRenderer: createFormItemEnum<GomokuPlayerType>({
          componentName: 'GomokuSettingPlayerType',
          choices: [
            GomokuPlayerType.HUMAN,
            GomokuPlayerType.COMPUTER,
            GomokuPlayerType.STUPID_COMPUTER,
          ],
        }),
      },
      pieceFill: {
        label: 'Avatar',
        disabled: isFinished,
        ContentRenderer: createFormItemBackground({
          componentName: 'GomokuSettingPlayerAvatar',
        }),
      },
    }),
    [isPending, isFinished],
  )

  const events = {
    onRealTimeChange: useEvent((data: IGomokuPlayerSettingsData): void => {
      dispatch({
        type: GomokuActionType.MODIFY_PLAYER,
        payload: {
          id: playerId,
          type: data.type,
          name: data.name,
          preference: removeUndefinedValues({
            pieceFillStyle: data.pieceFill,
            pieceStrokeStyle: data.pieceStroke,
          }),
        },
      })
    }),
    onSave: (data: IGomokuPlayerSettingsData): void => {
      events.onRealTimeChange(data)
      props.onClose()
    },
    onDiscard: useEvent((data: IGomokuPlayerSettingsData): void => {
      events.onRealTimeChange(data)
      props.onClose()
    }),
  }

  return (
    <React.Fragment>
      {props.visible && (
        <FormDialog<IGomokuPlayerSettingsData>
          container={props.containerRef.current}
          items={formItems}
          initialData={initialData}
          factoryData={factoryData}
          isResetAvailable={!isFinished}
          classes={formDialogClasses}
          onSave={events.onSave}
          onDiscard={events.onDiscard}
          onRealTimeChange={events.onRealTimeChange}
        />
      )}
    </React.Fragment>
  )
}

const formDialogClasses: IFormDialogClasses = mergeStyleSets({
  dialog: {
    minWidth: 240,
    minHeight: 400,
  },
  formItem: {
    margin: '1rem 1rem',
    alignItems: 'center',
  },
  label: {
    minWidth: '6rem',
  },
})
